type MeetingLiveInput struct {
	CommitteeName string
	CommitteeSlug string
	MeetingName   string
	IDString      string
	IsChair       bool
	CanManage     bool
	CanModerate   bool
	AgendaPoints  []AgendaPointItem
	Speakers      AttendeeSpeakersListPartialInput
	CurrentDoc    *LiveCurrentDocInfo
}

func (i *MeetingLiveInput) AttendeeLoginGet(ctx context.Context) templ.SafeURL {
	return templ.URL(paths.NewCommitteeSlugMeetingMeetingIdAttendeeLoginRoute(i.CommitteeSlug, i.IDString).AttendeeLoginPageGet(ctx, ""))
}

func (i *MeetingLiveInput) SSEStreamURL(ctx context.Context) templ.SafeURL {
	return templ.URL(paths.NewCommitteeSlugMeetingMeetingIdSpeakersStreamRoute(i.CommitteeSlug, i.IDString).AttendeeSpeakersStreamGet(ctx, ""))
}

func (i *MeetingLiveInput) ManageGet(ctx context.Context) templ.SafeURL {
	return templ.URL(paths.NewCommitteeSlugMeetingMeetingIdManageRoute(i.CommitteeSlug, i.IDString).CommitteeMeetingManageGet(ctx, ""))
}

func (i *MeetingLiveInput) ModerateGet(ctx context.Context) templ.SafeURL {
	return templ.URL(paths.NewCommitteeSlugMeetingMeetingIdModerateRoute(i.CommitteeSlug, i.IDString).MeetingModerateGet(ctx, ""))
}

func (i *MeetingLiveInput) CurrentAgendaPoint() *AgendaPointItem {
	for idx := range i.AgendaPoints {
		if i.AgendaPoints[idx].IsActive {
			return &i.AgendaPoints[idx]
		}
	}
	return nil
}

func (i *MeetingLiveInput) NextAgendaPoint() *AgendaPointItem {
	activeIdx := -1
	for idx := range i.AgendaPoints {
		if i.AgendaPoints[idx].IsActive {
			activeIdx = idx
			break
		}
	}
	if activeIdx == -1 || activeIdx+1 >= len(i.AgendaPoints) {
		return nil
	}
	return &i.AgendaPoints[activeIdx+1]
}

func (i *MeetingLiveInput) ScaffoldActions(ctx context.Context) []Action {
	var actions []Action
	if i.CanModerate {
		actions = append(actions, Action{
			Title: i18n.T(ctx, "meeting_live.moderate_button"),
			URL:   i.ModerateGet(ctx),
			Kind:  "info",
		})
	}
	if i.CanManage {
		actions = append(actions, Action{
			Title: i18n.T(ctx, "meeting_live.manage_button"),
			URL:   i.ManageGet(ctx),
			Kind:  "info",
		})
	}
	return actions
}

